module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);
// TODO: insert your code here
// Step1. 
// Save the input operands(dividend, divisor) when opn_valid is high.
// Step2.
// Initialize the shift register SR with the absolute value of the dividend, shifted left by one bit.
// Initialize the NEG_DIVISOR to the negated absolute value of the divisor.
// Initialize the counter cnt to 1, and start_cnt to 1 to begin the division process.
// Step3.
// If the counter cnt reaches 8, the division is complete.
// Clear cnt and start_cnt.
// The shift register SR is updated with the final remainder and quotient.
// Otherwise, the counter cnt is incremented, and the shift register SR is updated based on the subtraction result:
// Step4.
// Subtract the NEG_DIVISOR from SR.
// Step5.
// Use a multiplexer to select the appropriate result based on the carry-out.
// Step6.
// Update SR by inserting the carry-out into the least significant bit.
// Step7.
// Output valid result when cnt reaches 8.
// Remember to check the reset signal, the counter, and whether the result has been consumed.
// res_valid should be update directly, without passing middle register value.
// res_valid is set to zero if rst is high.
// Otherwise, if cnt is 8, res_valid is set to 1.
// Otherwise, if res_valid and res_ready is all high, res_valid is set to 0.
// Otherwise, res_valid is set to res_valid.
// HINT: You can use arithmetic operators(+) to implement subtraction.
// HINT: You can use ternary operator to implement multiplexer.
// HINT: Assign the result directly in one line.
// BEGIN
always @(posedge clk or negedge rst) begin
    if(!rst) begin
        res_valid <= 1'b0;
    end else begin
        if(cnt[3]) begin
            res_valid <= 1'b0;
        end else begin
            if(res_ready) begin
                res_valid <= 1'b0;
            end else begin
                res_valid <= res_valid;
            end
        end
    end
end
reg [3:0] cnt;
reg start_cnt;
always @(posedge clk or negedge rst) begin
    if(!rst) begin
        cnt <= 4'b0;
        start_cnt <= 1'b0;
    end else begin
        if(opn_valid) begin
            cnt <= 4'b1;
            start_cnt <= 1'b1;
        end else begin
            if(start_cnt) begin
                if(cnt>=4'b1000) begin
                    cnt <= 4'b0;
                    start_cnt <= 1'b0;
                end else begin
                    cnt <= cnt + 1'b1;
                    start_cnt <= start_cnt;
                end
            end else begin
                cnt <= cnt;
                start_cnt <= start_cnt;
            end
        end
    end
end
reg [16:0] sr;
reg [8:0] neg_divisor;
reg [7:0] divisor_temp;
reg [7:0] dividend_temp;
always @(posedge clk or negedge rst) begin
    if(!rst) begin
        divisor_temp <= 8'b0;
        dividend_temp <= 8'b0;
        neg_divisor <= 9'b0;
        sr <= 17'b0;
    end else begin
        if(opn_valid) begin
            divisor_temp <= divisor;
            dividend_temp <= dividend;
            neg_divisor <= {1'b1,~divisor}+9'b1;
            sr <= {9'b0,dividend,1'b0};
        end else begin
            if(start_cnt) begin
                if(cnt[3]) begin
                    if(sr[8]) begin
                        sr <= {1'b0,sr[16:9]+neg_divisor,sr[8:1]};
                    end else begin
                        sr <= {1'b1,sr[16:9]+neg_divisor[8:1],sr[8:1]};
                    end
                end else begin
                    sr <= sr;
                    if(sr[8]) begin
                        sr <= {1'b0,sr[16:9]+neg_divisor,sr[8:1]};
                    end else begin
                        sr <= {1'b1,sr[16:9]+neg_divisor[8:1],sr[8:1]};
                    end
                end
            end else begin
                sr <= sr;
            end
        end
    end
end
wire [8:0] sub_result;
assign sub_result = sr[16:8] + neg_divisor;
wire sr_insert_cout;
assign sr_insert_cout = sub_result[8];
wire [16:0] sr_result;
assign sr_result = sr[16:1] << 1;
assign result = {sr_result[15:8],sr_result[7:0]};
// END
endmodule
